import React from 'react';
import { Search } from './Search';
import './styles.css';

const items = [
  'React Hooks', 'React Context', 'React Router', 'React Memo',
  'Redux Toolkit', 'Redux Saga', 'Redux Thunk',
  'TypeScript Generics', 'TypeScript Unions', 'TypeScript Interfaces',
  'Node.js Express', 'Node.js Fastify', 'Node.js Koa',
  'CSS Grid', 'CSS Flexbox', 'CSS Variables',
  'GraphQL Queries', 'GraphQL Mutations', 'GraphQL Subscriptions',
  'Jest Testing', 'Vitest Testing', 'Cypress E2E',
];

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '28rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Tech Search</h1>
      <Search items={items} debounceMs={300} />
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import './styles.css';

interface SearchProps {
  items: string[];
  debounceMs: number;
}

// TODO: Add debounce to the search
// Currently filters on every keystroke — fix this

export const Search: React.FC<SearchProps> = ({ items, debounceMs }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<string[]>(items);
  const [isSearching, setIsSearching] = useState(false);

  // BUG: Filtering happens on every keystroke — no debounce!
  useEffect(() => {
    if (!query) {
      setResults(items);
      return;
    }
    // This should be debounced
    const filtered = items.filter(item =>
      item.toLowerCase().includes(query.toLowerCase())
    );
    setResults(filtered);
  }, [query, items]);

  return (
    <div className="search">
      <input
        data-testid="search-input"
        className="search__input"
        value={query}
        onChange={e => setQuery(e.target.value)}
        placeholder="Search technologies…"
      />

      {isSearching && (
        <p data-testid="searching" className="search__status">Searching…</p>
      )}

      <p data-testid="result-count" className="search__count">
        {results.length} results
      </p>

      <div className="search__results">
        {results.map((item, i) => (
          <div key={item} data-testid={`result-${i}`} className="search__item">
            {item}
          </div>
        ))}
      </div>
    </div>
  );
};

.search {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.search__input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.search__input:focus {
  outline: 2px solid #3b82f6;
  outline-offset: 1px;
}

.search__status {
  font-size: 0.8125rem;
  color: #f59e0b;
  font-style: italic;
}

.search__count {
  font-size: 0.8125rem;
  color: #6b7280;
}

.search__results {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.search__item {
  padding: 0.5rem 0.75rem;
  border-radius: 0.25rem;
  font-size: 0.875rem;
  color: #374151;
  background: #f9fafb;
}

