import { render, screen, fireEvent, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Debounced Search', () => {
  beforeEach(() => {
    jest.useFakeTimers();
  });

  afterEach(() => {
    jest.useRealTimers();
  });

  it('shows all items initially', () => {
    render(<App />);
    expect(screen.getByTestId('result-count')).toHaveTextContent('22 results');
  });

  it('shows searching indicator while debounce pending', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'react' } });
    expect(screen.getByTestId('searching')).toBeInTheDocument();
  });

  it('filters after debounce delay', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'react' } });
    act(() => { jest.advanceTimersByTime(300); });
    expect(screen.getByTestId('result-count')).toHaveTextContent('4 results');
  });

  it('hides searching indicator after debounce', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'react' } });
    act(() => { jest.advanceTimersByTime(300); });
    expect(screen.queryByTestId('searching')).not.toBeInTheDocument();
  });

  it('clearing input resets instantly', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'react' } });
    act(() => { jest.advanceTimersByTime(300); });
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: '' } });
    expect(screen.getByTestId('result-count')).toHaveTextContent('22 results');
  });

  it('resets debounce timer on continued typing', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'r' } });
    act(() => { jest.advanceTimersByTime(200); });
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 're' } });
    act(() => { jest.advanceTimersByTime(200); });
    // still pending
    expect(screen.getByTestId('searching')).toBeInTheDocument();
    act(() => { jest.advanceTimersByTime(100); });
    // now 300ms since last change
    expect(screen.queryByTestId('searching')).not.toBeInTheDocument();
  });
});

