import React, { useState, useEffect, useRef } from 'react';
import './styles.css';

interface SearchProps {
  items: string[];
  debounceMs: number;
}

export const Search: React.FC<SearchProps> = ({ items, debounceMs }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<string[]>(items);
  const [isSearching, setIsSearching] = useState(false);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    // Immediate clear
    if (!query) {
      setResults(items);
      setIsSearching(false);
      if (timerRef.current) clearTimeout(timerRef.current);
      return;
    }

    setIsSearching(true);

    timerRef.current = setTimeout(() => {
      const filtered = items.filter(item =>
        item.toLowerCase().includes(query.toLowerCase())
      );
      setResults(filtered);
      setIsSearching(false);
    }, debounceMs);

    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [query, items, debounceMs]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  return (
    <div className="search">
      <input
        data-testid="search-input"
        className="search__input"
        value={query}
        onChange={e => setQuery(e.target.value)}
        placeholder="Search technologies…"
      />

      {isSearching && (
        <p data-testid="searching" className="search__status">Searching…</p>
      )}

      <p data-testid="result-count" className="search__count">
        {results.length} results
      </p>

      <div className="search__results">
        {results.map((item, i) => (
          <div key={item} data-testid={`result-${i}`} className="search__item">
            {item}
          </div>
        ))}
      </div>
    </div>
  );
};
